4	describe("Game of Life - Next Generation", () => {
5	  const sorted = (cells: number[][]) => [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
6	
7	  it("should return empty grid when given empty grid", () => {
8	    expect(nextGeneration([])).toEqual([]);
9	  });
10	  it("should kill a single cell with no neighbors (underpopulation)", () => {
11	    expect(nextGeneration([[0, 0]])).toEqual([]);
12	  });
13	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
14	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
15	  });
16	  it("should keep a block pattern unchanged (still life with 2-3 neighbors)", () => {
17	    const block = [[0, 0], [1, 0], [0, 1], [1, 1]];
18	    const result = nextGeneration(block);
19	    expect(sorted(result)).toEqual(sorted(block));
20	  });
21	  it("should oscillate a blinker from vertical to horizontal (reproduction and underpopulation)", () => {
22	    const vertical = [[0, 0], [0, 1], [0, 2]];
23	    const result = nextGeneration(vertical);
24	    expect(sorted(result)).toEqual([[-1, 1], [0, 1], [1, 1]]);
25	  });
