1	const toKey = (x: number, y: number): string => `${x},${y}`;
2	
3	export const nextGeneration = (liveCells: number[][]): number[][] => {
4	  if (liveCells.length === 0) return [];
5	
6	  const alive = new Set(liveCells.map(([x, y]) => toKey(x, y)));
7	
8	  const neighborOffsets = [
9	    [-1, -1], [-1, 0], [-1, 1],
10	    [0, -1],           [0, 1],
11	    [1, -1],  [1, 0],  [1, 1],
12	  ];
13	
14	  const countNeighbors = (x: number, y: number): number =>
15	    neighborOffsets.filter(([dx, dy]) => alive.has(toKey(x + dx, y + dy))).length;
16	
17	  const candidates = new Set<string>();
18	  for (const [x, y] of liveCells) {
19	    candidates.add(toKey(x, y));
20	    for (const [dx, dy] of neighborOffsets) {
21	      candidates.add(toKey(x + dx, y + dy));
22	    }
23	  }
24	
25	  const result: number[][] = [];
26	  for (const key of candidates) {
27	    const [x, y] = key.split(",").map(Number);
28	    const neighbors = countNeighbors(x, y);
29	    if (neighbors === 3 || (neighbors === 2 && alive.has(key))) {
30	      result.push([x, y]);
31	    }
32	  }
33	
34	  return result;
35	};
